import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';

import './CreateCombinedMaterial.css';

const LaborHoursRecord = ({
    fetchAPI,
    apiBaseUrl,
    onClose
   
}) => {
    

    const [error, setError] = useState(null);
    const [employees, setEmployees] = useState([]);
    const [projects, setProjects] = useState([]);
    const [dayRecord, setDayRecord] = useState([]);

    const fetchData = useCallback(async () => {
        try {
            const projectsresponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
            const employeesresponse = await fetchAPI(`${apiBaseUrl}/employeesAPI`);
            setProjects(projectsresponse);
            setEmployees(employeesresponse);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setDayRecord((prevDayRecord) => ({
            ...prevDayRecord,
            [name]: value,
        }));
    };

    
    
    

    

    if (error) return <div>Error: {error}</div>;

    return (
        <div className="material-input-form-container">
            <div className="material-input-form">
                <h3>Combine Materials</h3>
                <span className="close-popup" onClick={onClose}>&times;</span>
                <div className="form-row">
                    <div className="form-group">
                        <label htmlFor="comboName">Combo Name</label>
                        <input
                            id="comboName"
                            type="text"
                            name="name"
                            value={dayRecord.name}
                            onChange={handleChange}
                            placeholder="Enter combined material name"
                            className="form-control"
                        />
                    </div>
                    <div className="form-group">
                        <label htmlFor="description">Description</label>
                        <textarea
                            id="description"
                            name="description"
                            value={dayRecord.description}
                            onChange={handleChange}
                            placeholder="Enter Description"
                            className="form-control"
                        />
                    </div>
                </div>

                {dayRecord.length > 0 && dayRecord.map((selection, index) => (
                    <div key={index} className="material-selection">
                        <div className="form-row">
                            <div className="form-group">
                                <label>Material Name:</label>
                                
                            </div>
                            <div className="form-group">
                                <label>Multiplier</label>
                                
                            </div>
                            <div className="form-group">
                                <label>Price</label>
                                
                            </div>

                            <div className="form-group">
                                <label>Sum</label>
                                
                            </div>
                            <div className="form-group">
                                <label>Comments</label>
                                
                            </div>
                            <div className="price-remove-container">
                                {dayRecord.length > 1 && (
                                    <button
                                        className="remove-btn"
            
                                    >
                                        Remove
                                    </button>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
                
                <button className="btn btn-primary add-btn">Add Material</button>
                <button className="btn btn-success save-btn" >Save Combined Material</button>
            </div>
        </div>
    );

};

export default LaborHoursRecord;
